const express = require('express');
const crypto  = require('crypto');
const app = express();
app.use(express.json());

app.post('/webhooks/orders', (req, res) => {
  res.status(200).json({ received: true }); // respond immediately
  processEvent(req.body, req.headers).catch(console.error);
});

async function processEvent(payload, headers) {
  const sig    = headers['x-webhook-signature'];
  const secret = process.env.WEBHOOK_SECRET;
  const body   = JSON.stringify(payload);
  const hash   = 'sha256=' + crypto.createHmac('sha256', secret).update(body).digest('hex');

  if (!crypto.timingSafeEqual(Buffer.from(hash), Buffer.from(sig))) {
    throw new Error('Invalid signature');
  }
  if (await isAlreadyProcessed(payload.event_id)) return;

  switch (payload.event) {
    case 'order.created':   await handleNewOrder(payload.data.order); break;
    case 'order.cancelled': await handleCancellation(payload.data.order); break;
  }

  await markAsProcessed(payload.event_id);
}
